							SkippedOnCooldown:         breakdown.SkippedOnCooldown,
							SkippedNeedsInvestigation: breakdown.SkippedNeedsInvestigation,
							SkippedBlocked:            breakdown.SkippedBlocked,
							SkippedNotEligible:        breakdown.SkippedNotEligible,
