package agentmetrics

import (
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"
	"sort"
	"strings"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
)

const (
	runStoreSubdir = ".ddx/exec/runs"
	bundlesSubdir  = ".ddx/executions"
)

// LoadAttempts scans the FEAT-010 run-store first, then .ddx/executions
// bundles, and returns one Attempt per execute-bead try. When the same
// AttemptID appears in both sources the run-store record wins. Attempts
// are returned sorted by StartedAt ascending (newest last) so callers
// computing windowed aggregations can take a tail slice.
func LoadAttempts(workingDir string) ([]Attempt, error) {
	enrich, err := loadRoutingEnrichment(workingDir)
	if err != nil {
		return nil, err
	}

	out := make([]Attempt, 0, 64)
	seen := make(map[string]bool)

	rs, err := loadFromRunStore(workingDir)
	if err != nil {
		return nil, err
	}
	for _, a := range rs {
		applyEnrichment(&a, enrich)
		a.Bucket = ClassifyBucket(a.Status)
		a.Tier = TierKey(a.Harness, a.Model)
		out = append(out, a)
		seen[a.AttemptID] = true
	}

	bd, err := loadFromBundles(workingDir)
	if err != nil {
		return nil, err
	}
	for _, a := range bd {
		if seen[a.AttemptID] {
			continue
		}
		applyEnrichment(&a, enrich)
		a.Bucket = ClassifyBucket(a.Status)
		a.Tier = TierKey(a.Harness, a.Model)
		out = append(out, a)
		seen[a.AttemptID] = true
	}

	sort.SliceStable(out, func(i, j int) bool {
		return out[i].StartedAt.Before(out[j].StartedAt)
	})
	return out, nil
}

// TierKey is the canonical "harness/model" tier label used by other Story
// 11 surfaces. An empty model collapses to just the harness.
func TierKey(harness, model string) string {
	if model == "" {
		return harness
	}
	return harness + "/" + model
}

// runRecord mirrors the FEAT-010 run-store JSON shape (subset). Mirrors
// server/state_runs.go runRecord; intentionally not shared so this package
// stays free of the server import graph.
type runRecord struct {
	ID          string  `json:"id"`
	Layer       string  `json:"layer"`
	Status      string  `json:"status"`
	Outcome     string  `json:"outcome"`
	StartedAt   string  `json:"started_at"`
	CompletedAt string  `json:"completed_at"`
	BeadID      string  `json:"bead_id"`
	Harness     string  `json:"harness"`
	Provider    string  `json:"provider"`
	Model       string  `json:"model"`
	CostUSD     float64 `json:"cost_usd"`
	DurationMs  int     `json:"duration_ms"`
	ExitCode    int     `json:"exit_code"`
	TokensIn    int     `json:"tokens_in"`
	TokensOut   int     `json:"tokens_out"`
}

func loadFromRunStore(workingDir string) ([]Attempt, error) {
	dir := filepath.Join(workingDir, runStoreSubdir)
	entries, err := os.ReadDir(dir)
	if err != nil {
		if os.IsNotExist(err) {
			return nil, nil
		}
		return nil, fmt.Errorf("read run store: %w", err)
	}
	out := make([]Attempt, 0, len(entries))
	for _, entry := range entries {
		if entry.IsDir() || !strings.HasSuffix(entry.Name(), ".json") {
			continue
		}
		raw, err := os.ReadFile(filepath.Join(dir, entry.Name()))
		if err != nil {
			continue
		}
		var rec runRecord
		if err := json.Unmarshal(raw, &rec); err != nil || rec.ID == "" {
			continue
		}
		// Only try-layer records correspond to execute-bead attempts.
		// Run-layer records (per-invocation harness sessions) are noise
		// for Story 11 aggregations; skip them. Empty layer is treated
		// as try for forward-compat with writers that omit it.
		layer := strings.ToLower(rec.Layer)
		if layer != "" && layer != "try" {
			continue
		}
		a := Attempt{
			AttemptID:    rec.ID,
			BeadID:       rec.BeadID,
			Harness:      rec.Harness,
			Provider:     rec.Provider,
			Model:        rec.Model,
			Status:       rec.Status,
			Outcome:      rec.Outcome,
			CostUSD:      rec.CostUSD,
			DurationMS:   rec.DurationMs,
			ExitCode:     rec.ExitCode,
			InputTokens:  rec.TokensIn,
			OutputTokens: rec.TokensOut,
			StartedAt:    parseTime(rec.StartedAt),
			FinishedAt:   parseTime(rec.CompletedAt),
			Source:       SourceRunStore,
		}
		out = append(out, a)
	}
	return out, nil
}

// bundleResult mirrors the subset of agent.ExecuteBeadResult this loader
// reads. Kept local so the package does not depend on the agent package.
type bundleResult struct {
	BeadID     string    `json:"bead_id"`
	AttemptID  string    `json:"attempt_id"`
	Outcome    string    `json:"outcome"`
	Status     string    `json:"status"`
	Harness    string    `json:"harness"`
	Provider   string    `json:"provider"`
	Model      string    `json:"model"`
	DurationMS int       `json:"duration_ms"`
	CostUSD    float64   `json:"cost_usd"`
	ExitCode   int       `json:"exit_code"`
	StartedAt  time.Time `json:"started_at"`
	FinishedAt time.Time `json:"finished_at"`
}

func loadFromBundles(workingDir string) ([]Attempt, error) {
	dir := filepath.Join(workingDir, bundlesSubdir)
	entries, err := os.ReadDir(dir)
	if err != nil {
		if os.IsNotExist(err) {
			return nil, nil
		}
		return nil, fmt.Errorf("read bundles dir: %w", err)
	}
	out := make([]Attempt, 0, len(entries))
	for _, entry := range entries {
		if !entry.IsDir() {
			continue
		}
		bundleID := entry.Name()
		resultPath := filepath.Join(dir, bundleID, "result.json")
		raw, err := os.ReadFile(resultPath)
		if err != nil {
			continue
		}
		var res bundleResult
		if err := json.Unmarshal(raw, &res); err != nil {
			continue
		}
		attemptID := res.AttemptID
		if attemptID == "" {
			attemptID = bundleID
		}
		out = append(out, Attempt{
			AttemptID:  attemptID,
			BeadID:     res.BeadID,
			Harness:    res.Harness,
			Provider:   res.Provider,
			Model:      res.Model,
			Status:     res.Status,
			Outcome:    res.Outcome,
			CostUSD:    res.CostUSD,
			DurationMS: res.DurationMS,
			ExitCode:   res.ExitCode,
			StartedAt:  res.StartedAt,
			FinishedAt: res.FinishedAt,
			Source:     SourceBundle,
		})
	}
	return out, nil
}

// routingFacts is the harness/provider/model the most recent kind:routing
// or kind:escalation-summary event recorded for a bead. Used to fill in
// blanks on legacy attempts whose result.json predates those fields.
type routingFacts struct {
	Harness  string
	Provider string
	Model    string
}

// loadRoutingEnrichment scans the bead store and indexes the most recent
// routing/escalation-summary facts per bead. Best-effort: a missing or
// unreadable bead store yields an empty map, never an error, since the
// loader still has authoritative data on each result.
func loadRoutingEnrichment(workingDir string) (map[string]routingFacts, error) {
	store := bead.NewStore(filepath.Join(workingDir, ".ddx"))
	beads, err := store.ReadAll()
	if err != nil {
		// Return an empty map so missing bead store does not abort
		// metrics loading.
		return map[string]routingFacts{}, nil
	}
	out := make(map[string]routingFacts, len(beads))
	for _, b := range beads {
		facts := routingFromExtra(b.Extra)
		if facts.Harness == "" && facts.Provider == "" && facts.Model == "" {
			continue
		}
		out[b.ID] = facts

// Package bead implements the on-disk bead tracker.
//
// Size envelope (ddx-f8a11202):
//
// Individual bead fields — description, acceptance, notes, and each event's
// body — are bounded by MaxFieldBytes (65,535 bytes). This matches upstream
// bd's Dolt TEXT column limit so DDx-authored beads can always round-trip
// through `bd import`. Writers exceeding the cap are truncated with a
// `…[truncated, N bytes]` marker at AppendEvent; callers that need to
// preserve the full payload (notably reviewer streams) should persist to a
// sidecar artifact under `.ddx/executions/<id>/` and record a path
// reference in the event body.
//
// On the read side, scanners use a 16MB buffer — real-world incidents have
// produced 1.46MB bead rows and ~7MB session-log rows when writers bypassed
// the cap. 16MB comfortably fits a bead with dozens of maxed-out fields and
// matches the scanner in the agent package.
package bead

import (
	"bufio"
	"bytes"
	"context"
	"crypto/rand"
	"encoding/hex"
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"
	"sort"
	"strconv"
	"strings"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/config"
	gitpkg "github.com/DocumentDrivenDX/ddx/internal/git"
)

// Store manages beads via a pluggable backend.
type Store struct {
	Collection string
	Dir        string
	File       string
	Prefix     string
	LockDir    string
	LockWait   time.Duration
	backend    RawBackend // nil means use built-in JSONL
}

// Compile-time check: *Store satisfies the high-level Backend interface
// declared in backend.go. This is the contract chaos_test.go and (eventually)
// cli/cmd callers program against.
var _ Backend = (*Store)(nil)

type StoreOption func(*Store)

// WithCollection selects the logical bead collection. The default collection
// remains "beads", which maps to "beads.jsonl" in the JSONL backend.
func WithCollection(name string) StoreOption {
	return func(s *Store) {
		if cleaned := normalizeCollection(name); cleaned != "" {
			s.Collection = cleaned
		}
	}
}

// NewStore creates a store with the given directory.
// Defaults can be overridden via options or environment.
func NewStore(dir string, opts ...StoreOption) *Store {
	if dir == "" {
		dir = envOr("DDX_BEAD_DIR", ".ddx")
	}
	workingDir := dir
	if filepath.Base(dir) == ".ddx" {
		workingDir = filepath.Dir(dir)
	}
	prefix := envOr("DDX_BEAD_PREFIX", "")
	var configBackend string
	if cfg, err := config.LoadWithWorkingDir(workingDir); err == nil && cfg != nil && cfg.Bead != nil {
		if prefix == "" && cfg.Bead.IDPrefix != "" {
			prefix = cfg.Bead.IDPrefix
		}
		configBackend = cfg.Bead.Backend
	}
	if prefix == "" {
		prefix = detectPrefix(workingDir)
	}
	// Backend selection: env var wins, then config, then jsonl default.
	backendType := os.Getenv("DDX_BEAD_BACKEND")
	if backendType == "" {
		backendType = configBackend
	}
	if backendType == "" {
		backendType = BackendJSONL
	}

	s := &Store{
		Collection: DefaultCollection,
		Dir:        dir,
		Prefix:     prefix,
		LockWait:   parseDurationOr("DDX_BEAD_LOCK_TIMEOUT", 10*time.Second),
	}
	for _, opt := range opts {
		if opt != nil {
			opt(s)
		}
	}
	spec := DefaultRegistry().Resolve(CollectionID(s.Collection))
	s.File, s.LockDir = spec.PathsUnder(dir)

	// Set up external backend if configured. bd/br lack per-collection
	// scoping in their CLI, so non-default collections (e.g. beads-archive)
	// route through a JSONL fallback the external backend transparently
	// delegates to. The default collection always goes straight to bd/br
	// to preserve the existing interchange contract (schema_compat_test.go,
	// import/export round-trip).
	switch backendType {
	case BackendBD, BackendBR:
		var fallback RawBackend
		if s.Collection != DefaultCollection {
			fallback = NewJSONLBackend(s.Dir, s.File, s.LockDir, s.LockWait)
		}
		if ext, err := NewExternalBackendWithFallback(backendType, s.Collection, fallback); err == nil {
			s.backend = ext
		}
		// Fall through to JSONL if tool not available
	case BackendAxon:
		s.backend = NewAxonBackend(s.Dir, s.LockWait)
	}

	return s
}

// NewStoreWithCollection creates a store for a named logical collection.
func NewStoreWithCollection(dir, collection string) *Store {
	return NewStore(dir, WithCollection(collection))
}

// Init creates the storage directory and file.
func (s *Store) Init() error {
	if s.backend != nil {
		return s.backend.Init()
	}
	if err := os.MkdirAll(s.Dir, 0o755); err != nil {
		return fmt.Errorf("bead: init dir: %w", err)
	}
	f, err := os.OpenFile(s.File, os.O_CREATE|os.O_WRONLY, 0o644)
	if err != nil {
		return fmt.Errorf("bead: init file: %w", err)
	}
	return f.Close()
}

// GenID generates a unique bead ID with the configured prefix.
func (s *Store) GenID() (string, error) {
	b := make([]byte, 4)
	if _, err := rand.Read(b); err != nil {
		return "", fmt.Errorf("bead: gen id: %w", err)
	}
	return fmt.Sprintf("%s-%s", s.Prefix, hex.EncodeToString(b)), nil
}

// ReadAll loads all beads from the configured backend.
func (s *Store) ReadAll() ([]Bead, error) {
	return s.ReadAllFiltered(nil)
}

// ReadAllFiltered loads all beads, folds them by latest-wins, and returns only
// those for which the predicate returns true. When the predicate is nil every
// bead is returned (equivalent to ReadAll). The predicate is applied at the
// per-entry parse boundary after fold — matched beads are appended directly to
// the return slice without first being held in an intermediate full-corpus
// list, so queries that match a small subset avoid materializing the
// mismatches (ddx-9ce6842a Part 2 step 2: filter pushdown).
func (s *Store) ReadAllFiltered(pred func(Bead) bool) ([]Bead, error) {
	if s.backend != nil {
		all, err := s.backend.ReadAll()
		if err != nil {
			return nil, err
		}
		if pred == nil {
			return all, nil
		}
		out := make([]Bead, 0, len(all))
		for _, b := range all {
			if pred(b) {
				out = append(out, b)
			}
		}
		return out, nil
	}
	beads, warnings, err := s.readAllRaw()
	if err != nil {
		return nil, fmt.Errorf("bead: read %s: %w", s.File, err)
	}
	beads = foldLatestBeads(beads)
	for _, warning := range warnings {
		fmt.Fprintln(os.Stderr, warning)
	}
	if len(warnings) > 0 && len(beads) > 0 {
		repaired, repairErr := s.repairJSONL()
		if repairErr != nil {
			return beads, fmt.Errorf("bead: repair %s: %w", s.File, repairErr)
		}
		if repaired {
			fmt.Fprintf(os.Stderr, "bead: repaired %s; backup written to %s.bak\n", s.File, s.File)
		}
	}
	if len(beads) == 0 && len(warnings) > 0 {
		return nil, fmt.Errorf("bead: read %s: %d malformed record(s), 0 valid", s.File, len(warnings))
	}
	if pred == nil {
		return beads, nil
	}
	out := make([]Bead, 0, len(beads))
	for _, b := range beads {
		if pred(b) {
			out = append(out, b)
		}
	}

func GenerateSessionID() string {
	b := make([]byte, 4)
	_, _ = rand.Read(b)
	return "eb-" + hex.EncodeToString(b)
}

// appendBeadRoutingEvidence records a kind:routing evidence entry on the bead
// after an agent run. It is a best-effort operation — errors are silently
// ignored so a store failure never aborts the main execute-bead flow.
//
// The body separates requested passthrough constraints (harness/provider/model
// from the CLI envelope) and requested power bounds from the actual resolved
// values so analytics can distinguish intent from outcome (AC5 of ddx-20047dd5).
func appendBeadRoutingEvidence(appender BeadEventAppender, beadID, harness, provider, model, routeReason, baseURL string, passthrough config.AgentPassthrough, minPower, maxPower, actualPower int) {
	if appender == nil || beadID == "" {
		return
	}
	resolvedProvider := provider
	if resolvedProvider == "" {
		resolvedProvider = harness
	}
	type routingBody struct {
		ResolvedProvider  string   `json:"resolved_provider"`
		ResolvedModel     string   `json:"resolved_model,omitempty"`
		RouteReason       string   `json:"route_reason,omitempty"`
		FallbackChain     []string `json:"fallback_chain"`
		BaseURL           string   `json:"base_url,omitempty"`
		RequestedHarness  string   `json:"requested_harness,omitempty"`
		RequestedProvider string   `json:"requested_provider,omitempty"`
		RequestedModel    string   `json:"requested_model,omitempty"`
		RequestedMinPower int      `json:"requested_min_power,omitempty"`
		RequestedMaxPower int      `json:"requested_max_power,omitempty"`
		ActualPower       int      `json:"actual_power,omitempty"`
	}
	body := routingBody{
		ResolvedProvider:  resolvedProvider,
		ResolvedModel:     model,
		RouteReason:       routeReason,
		FallbackChain:     []string{},
		BaseURL:           baseURL,
		RequestedHarness:  passthrough.Harness,
		RequestedProvider: passthrough.Provider,
		RequestedModel:    passthrough.Model,
		RequestedMinPower: minPower,
		RequestedMaxPower: maxPower,
		ActualPower:       actualPower,
	}
	data, err := json.Marshal(body)
	if err != nil {
		return
	}
	summary := fmt.Sprintf("provider=%s", resolvedProvider)
	if model != "" {
		summary += fmt.Sprintf(" model=%s", model)
	}
	if routeReason != "" {
		summary += fmt.Sprintf(" reason=%s", routeReason)
	}
	_ = appender.AppendEvent(beadID, bead.BeadEvent{
		Kind:    "routing",
		Summary: summary,
		Body:    string(data),
		Actor:   "ddx",
		Source:  "ddx agent execute-bead",
	})
}

// costEventBody is the JSON shape persisted in a kind:cost evidence event.
// `ddx bead metrics aggregate` reads these directly so cost rollup never
// has to join against the session index.
type costEventBody struct {
	AttemptID    string  `json:"attempt_id"`
	Harness      string  `json:"harness,omitempty"`
	Provider     string  `json:"provider,omitempty"`
	Model        string  `json:"model,omitempty"`
	InputTokens  int     `json:"input_tokens"`
	OutputTokens int     `json:"output_tokens"`
	TotalTokens  int     `json:"total_tokens"`
	CostUSD      float64 `json:"cost_usd"`
	DurationMS   int     `json:"duration_ms"`
	ExitCode     int     `json:"exit_code"`
}

// appendBeadCostEvidence records a kind:cost evidence entry on the bead with
// per-attempt token and dollar usage. Best-effort: errors are discarded so a
// store failure never aborts the main execute-bead flow. Emits nothing when
// the appender is nil, the beadID is empty, or every cost field is zero
// (e.g., dry-run, no-changes with no provider call).
func appendBeadCostEvidence(appender BeadEventAppender, beadID, attemptID string, body costEventBody) {
	if appender == nil || beadID == "" {
		return
	}
	if body.InputTokens == 0 && body.OutputTokens == 0 && body.TotalTokens == 0 && body.CostUSD == 0 {
		return
	}
	body.AttemptID = attemptID
	if body.TotalTokens == 0 {
		body.TotalTokens = body.InputTokens + body.OutputTokens
	}
	data, err := json.Marshal(body)
	if err != nil {
		return
	}
	var summary string
	if body.CostUSD > 0 {
		summary = fmt.Sprintf("tokens=%d cost_usd=%.4f", body.TotalTokens, body.CostUSD)
	} else {
		summary = fmt.Sprintf("tokens=%d", body.TotalTokens)
	}
	if body.Model != "" {
		summary += fmt.Sprintf(" model=%s", body.Model)
	}
	_ = appender.AppendEvent(beadID, bead.BeadEvent{
		Kind:    "cost",
		Summary: summary,
		Body:    string(data),
		Actor:   "ddx",
		Source:  "ddx agent execute-bead",
	})
}

// appendRateLimitRetryEvent records one rate-limit retry on the bead's
// event stream per TD-031 §4 / §8.4 RateLimitRetryContract. The event body
// carries the retry count and wait duration so an audit can reconstruct the
// pause without consulting routing logs.
func appendRateLimitRetryEvent(appender BeadEventAppender, beadID string, info RateLimitRetryInfo) {
	if appender == nil || beadID == "" {
		return
	}
	body := map[string]any{
		"attempt":     info.Attempt,
		"wait_ms":     info.Wait.Milliseconds(),
		"source":      info.Source,
		"elapsed_ms":  info.Elapsed.Milliseconds(),
		"over_budget": info.OverBudget,
	}
	if info.Result != nil {
		if info.Result.Harness != "" {
			body["harness"] = info.Result.Harness
		}
		if info.Result.Provider != "" {
			body["provider"] = info.Result.Provider
		}
		if info.Result.Model != "" {
			body["model"] = info.Result.Model
		}
	}
	data, err := json.Marshal(body)
	if err != nil {
		return
	}
	summary := fmt.Sprintf("attempt=%d wait=%s source=%s", info.Attempt, info.Wait.Round(time.Millisecond), info.Source)
	if info.OverBudget {
		summary = "budget exhausted: " + RateLimitBudgetExhaustedReason
	}
	_ = appender.AppendEvent(beadID, bead.BeadEvent{
		Kind:    RateLimitRetryEventKind,
		Summary: summary,
		Body:    string(data),
		Actor:   "ddx",
		Source:  "ddx agent execute-bead",
	})
}

// ExecuteBeadWithConfig is the thin worker: it creates an isolated worktree,
// constructs the agent prompt from bead context, runs the agent harness,
// synthesizes a commit if the agent left uncommitted changes, then cleans up
// the worktree and returns the result. It classifies outcomes as exactly one
// of:
//
//   - task_succeeded: agent exited 0 and produced one or more commits
//   - task_failed:    agent exited non-zero
//   - task_no_changes: agent exited 0, made no commits, and wrote a rationale
//   - task_no_evidence: agent exited 0 but made no commits and wrote no rationale
//
// Merge, UpdateRef, gate evaluation, preserve-ref management, and orphan
// recovery are the parent's responsibility (see LandBeadResult, RecoverOrphans).
//
// Agent dispatch: production callers leave runtime.Service and runtime.AgentRunner
// nil. ExecuteBeadWithConfig constructs a fresh agentlib.FizeauService from
// projectRoot via NewServiceFromWorkDir and dispatches via RunViaServiceWith.
// Tests may set runtime.AgentRunner to inject a fake that returns canned
// Result values; when set, it takes precedence over the service path.
func ExecuteBeadWithConfig(ctx context.Context, projectRoot string, beadID string, rcfg config.ResolvedConfig, runtime ExecuteBeadRuntime, gitOps GitOps) (*ExecuteBeadResult, error) {
	if ctx == nil {
		ctx = context.Background()
	}
	if runtime.WorkerID == "" {
		runtime.WorkerID = os.Getenv("DDX_WORKER_ID")
	}

	resourceChecker := runtime.ResourceChecker
	if resourceChecker == nil {
		resourceChecker = NewExecutionResourceChecker(projectRoot, gitOps)
	}
	if _, err := resourceChecker.Check(ctx); err != nil {
		var resourceErr *ResourceExhaustedError
		if errors.As(err, &resourceErr) {
			res := &ExecuteBeadResult{
				BeadID:            beadID,
				WorkerID:          runtime.WorkerID,
				ExitCode:          1,
				Error:             resourceErr.Error(),
				Reason:            resourceErr.Error(),
				Outcome:           ExecuteBeadOutcomeTaskFailed,
				Status:            ExecuteBeadStatusResourceExhausted,
				ResourceExhausted: &resourceErr.Result,
			}
			res.FailureMode = ClassifyFailureMode(res.Outcome, res.ExitCode, res.Error)
			return res, nil
		}
		return nil, err
	}

	attemptID := GenerateAttemptID()
	wtPath := executeBeadWorktreePath(beadID, attemptID)
	if mkErr := os.MkdirAll(filepath.Dir(wtPath), 0o755); mkErr != nil {
		return nil, fmt.Errorf("creating execute-bead worktree parent dir: %w", mkErr)
	}

	// Commit beads.jsonl before spawning worktree so the worktree snapshot
	// includes any bead metadata updates (e.g. spec-id).
	if err := CommitTracker(projectRoot); err != nil {
		return nil, err
	}

	// Checkpoint any remaining caller dirt as a real commit on the current
	// branch (FEAT-012 §22, US-126 AC#1). The new HEAD becomes the effective
	// base for the worker worktree; caller's edits are preserved as a normal
	// commit they can `git reset HEAD~` if they want them back uncommitted.
	if _, err := gitOps.SynthesizeCommit(projectRoot, "chore: checkpoint pre-execute-bead "+attemptID); err != nil {
		return nil, fmt.Errorf("pre-execute-bead checkpoint: %w", err)
	}

	// Resolve base revision after the tracker + checkpoint commits.
	baseRev, err := resolveBase(gitOps, projectRoot, runtime.FromRev)
	if err != nil {
		return nil, err
	}

	// Create the isolated worktree. Orphan recovery is the parent's responsibility
	// (call RecoverOrphans before invoking workers).
	if err := gitOps.WorktreeAdd(projectRoot, wtPath, baseRev); err != nil {
		_ = os.RemoveAll(wtPath)
		return nil, fmt.Errorf("creating isolated worktree: %w", err)
	}
	defer func() {
		_ = gitOps.WorktreeRemove(projectRoot, wtPath)
	}()

	// Publish the live run-state so operators and HELIX can observe what is
	// executing without polling the bead tracker (CONTRACT-001 §5). The file
	// is removed on completion; a crashed worker leaves a stale file that
	// RecoverOrphans sweeps before the next attempt.
	_ = WriteRunState(projectRoot, RunState{
		BeadID:       beadID,
		AttemptID:    attemptID,
		Harness:      rcfg.Harness(),
		Model:        rcfg.Model(),
		StartedAt:    time.Now().UTC(),
		WorktreePath: wtPath,

package agent

import (
	"os"
	"os/exec"
	"path/filepath"
	"strings"
	"testing"
)

// TestExecuteBeadLandsEvidence is the AC (1) regression test: a simulated
// successful execute-bead attempt against a real temp git repo asserts that
// (a) after the run returns the working tree is clean, and (b) at least one
// file under .ddx/executions/<attempt-id>/ is present in a committed state.
// AC (2): the worker's closing_commit_sha still resolves after the merge.
func TestExecuteBeadLandsEvidence(t *testing.T) {
	r := newLandTestRepo(t)

	// Simulate the orchestrator materializing evidence files in the project root.
	attemptID := "20260416T181205-aabb1122"
	evidenceDir := filepath.Join(".ddx", "executions", attemptID)
	fullDir := filepath.Join(r.dir, evidenceDir)
	if err := os.MkdirAll(fullDir, 0o755); err != nil {
		t.Fatal(err)
	}
	writeEvidenceFile(t, fullDir, "manifest.json", `{"attempt_id":"`+attemptID+`","bead_id":"ddx-evidence-test"}`)
	writeEvidenceFile(t, fullDir, "result.json", `{"status":"success","bead_id":"ddx-evidence-test"}`)
	writeEvidenceFile(t, fullDir, "prompt.md", "# Prompt\nExecute bead ddx-evidence-test")

	// Create a worker commit (simulates agent output).
	workerSHA := r.commitOn(r.baseSHA, "feature.txt", "feature content\n", "feat: implement feature [ddx-evidence-test]")

	// Land with evidence — fast-forward path.
	req := LandRequest{
		WorktreeDir:  r.dir,
		BaseRev:      r.baseSHA,
		ResultRev:    workerSHA,
		BeadID:       "ddx-evidence-test",
		AttemptID:    attemptID,
		TargetBranch: "main",
		EvidenceDir:  filepath.ToSlash(evidenceDir),
	}
	land, err := Land(r.dir, req, RealLandingGitOps{})
	if err != nil {
		t.Fatalf("Land: %v", err)
	}
	if land.Status != "landed" {
		t.Fatalf("expected status=landed, got %q (reason=%q)", land.Status, land.Reason)
	}

	// AC (1a): working tree is clean (git status --porcelain is empty).
	statusOut := r.runGit("status", "--porcelain")
	if strings.TrimSpace(statusOut) != "" {
		t.Errorf("AC 1a FAILED: working tree not clean after Land:\n%s", statusOut)
	}

	// AC (1b): at least one file under .ddx/executions/<attempt-id>/ is present
	// in git log for the result or successor commit.
	logOut := r.runGit("log", "--all", "--oneline", "--name-only")
	evidenceManifestPath := filepath.ToSlash(filepath.Join(evidenceDir, "manifest.json"))
	if !strings.Contains(logOut, evidenceManifestPath) {
		t.Errorf("AC 1b FAILED: %s not found in git log:\n%s", evidenceManifestPath, logOut)
	}

	// Evidence commit was created and NewTip advanced past the worker commit.
	if land.EvidenceCommitSHA == "" {
		t.Errorf("expected EvidenceCommitSHA to be set")
	}
	if land.NewTip == workerSHA {
		t.Errorf("NewTip should be the evidence commit, not the worker commit")
	}
	if land.NewTip != land.EvidenceCommitSHA {
		t.Errorf("NewTip (%s) != EvidenceCommitSHA (%s)", land.NewTip, land.EvidenceCommitSHA)
	}

	// AC (2): closing_commit_sha (the tip that will be recorded) still resolves.
	checkCmd := exec.Command("git", "-C", r.dir, "cat-file", "-e", land.NewTip)
	if err := checkCmd.Run(); err != nil {
		t.Errorf("AC 2 FAILED: closing_commit_sha %s does not resolve: %v", land.NewTip, err)
	}
	// The worker's original commit must also still resolve.
	checkCmd = exec.Command("git", "-C", r.dir, "cat-file", "-e", workerSHA)
	if err := checkCmd.Run(); err != nil {
		t.Errorf("AC 2 FAILED: worker commit %s no longer resolves: %v", workerSHA, err)
	}
	// Worker commit must be reachable from main.
	if !r.shaReachable("refs/heads/main", workerSHA) {
		t.Errorf("worker commit %s not reachable from main", workerSHA)
	}
}

// TestExecuteBeadLandsEvidence_MergePath exercises the merge path (target
// branch has advanced since the worker started) and verifies evidence is
// committed and the worktree is clean.
func TestExecuteBeadLandsEvidence_MergePath(t *testing.T) {
	r := newLandTestRepo(t)

	attemptID := "20260416T181206-ccdd3344"
	evidenceDir := filepath.Join(".ddx", "executions", attemptID)
	fullDir := filepath.Join(r.dir, evidenceDir)
	if err := os.MkdirAll(fullDir, 0o755); err != nil {
		t.Fatal(err)
	}
	writeEvidenceFile(t, fullDir, "manifest.json", `{"attempt_id":"`+attemptID+`"}`)
	writeEvidenceFile(t, fullDir, "result.json", `{"status":"merged"}`)

	// Worker branches off baseSHA.
	workerSHA := r.commitOn(r.baseSHA, "feature.txt", "feature\n", "feat: worker")

	// Sibling advances main. Sync the working tree so it matches siblingSHA's
	// tree — update-ref alone only moves the ref, leaving the working tree stale.
	siblingSHA := r.commitOn(r.baseSHA, "sibling.txt", "sibling\n", "feat: sibling")
	r.runGit("update-ref", "refs/heads/main", siblingSHA)
	r.runGit("read-tree", "HEAD")
	r.runGit("checkout-index", "-f", "-a")

	req := LandRequest{
		WorktreeDir:  r.dir,
		BaseRev:      r.baseSHA,
		ResultRev:    workerSHA,
		BeadID:       "ddx-evidence-merge",
		AttemptID:    attemptID,
		TargetBranch: "main",
		EvidenceDir:  filepath.ToSlash(evidenceDir),
	}
	land, err := Land(r.dir, req, RealLandingGitOps{})
	if err != nil {
		t.Fatalf("Land: %v", err)
	}
	if land.Status != "landed" {
		t.Fatalf("expected landed, got %q", land.Status)
	}
	if !land.Merged {
		t.Errorf("expected Merged=true on merge path")
	}

	statusOut := r.runGit("status", "--porcelain")
	if strings.TrimSpace(statusOut) != "" {
		t.Errorf("working tree not clean after merge-path land:\n%s", statusOut)
	}

	if land.EvidenceCommitSHA == "" {
		t.Errorf("expected EvidenceCommitSHA on merge path")
	}

	// Worker commit still resolves (closing_commit_sha contract).
	checkCmd := exec.Command("git", "-C", r.dir, "cat-file", "-e", workerSHA)
	if err := checkCmd.Run(); err != nil {
		t.Errorf("worker SHA %s doesn't resolve after merge: %v", workerSHA, err)
	}
	if !r.shaReachable("refs/heads/main", workerSHA) {
		t.Errorf("worker commit %s not reachable from main after merge", workerSHA)
	}
}

// TestLandNoEvidenceDir verifies that when EvidenceDir is empty, no evidence
// commit is created and behavior matches the pre-fix code path.
func TestLandNoEvidenceDir(t *testing.T) {
	r := newLandTestRepo(t)

	workerSHA := r.commitOn(r.baseSHA, "feature.txt", "hello\n", "feat: hello")

	req := LandRequest{
		WorktreeDir:  r.dir,
		BaseRev:      r.baseSHA,
		ResultRev:    workerSHA,
		BeadID:       "ddx-no-evidence",
		AttemptID:    "20260416T181207-eeff5566",
		TargetBranch: "main",
	}
	land, err := Land(r.dir, req, RealLandingGitOps{})
	if err != nil {
		t.Fatalf("Land: %v", err)
	}
	if land.Status != "landed" {
		t.Fatalf("expected landed, got %q", land.Status)
	}
	if land.EvidenceCommitSHA != "" {
		t.Errorf("expected no evidence commit, got %s", land.EvidenceCommitSHA)
	}
	if land.NewTip != workerSHA {
		t.Errorf("NewTip = %s, want %s (no evidence commit)", land.NewTip, workerSHA)
	}
}

// TestVerifyCleanWorktree verifies the safety net: VerifyCleanWorktree
// commits leftover evidence files that the land flow did not pick up.
func TestVerifyCleanWorktree(t *testing.T) {
	r := newLandTestRepo(t)

	attemptID := "20260416T181208-verify01"
	evidenceDir := filepath.Join(r.dir, ExecuteBeadArtifactDir, attemptID)
	if err := os.MkdirAll(evidenceDir, 0o755); err != nil {
		t.Fatal(err)
	}
	writeEvidenceFile(t, evidenceDir, "result.json", `{"status":"test"}`)

	// Before VerifyCleanWorktree, evidence is untracked.
	statusBefore := r.runGit("status", "--porcelain", "--", filepath.ToSlash(filepath.Join(ExecuteBeadArtifactDir, attemptID)))
	if strings.TrimSpace(statusBefore) == "" {
		t.Fatal("expected untracked evidence files before verification")
	}

	if err := VerifyCleanWorktree(r.dir, attemptID); err != nil {
		t.Fatalf("VerifyCleanWorktree: %v", err)
	}

	// After, evidence dir should be clean.
	statusAfter := r.runGit("status", "--porcelain", "--", filepath.ToSlash(filepath.Join(ExecuteBeadArtifactDir, attemptID)))
	if strings.TrimSpace(statusAfter) != "" {
		t.Errorf("evidence dir still dirty after VerifyCleanWorktree:\n%s", statusAfter)
	}
}

// TestVerifyCleanWorktreeNoOp verifies VerifyCleanWorktree is a no-op
// when the evidence dir is already committed.
func TestVerifyCleanWorktreeNoOp(t *testing.T) {
	r := newLandTestRepo(t)

	attemptID := "20260416T181209-noop0001"
	if err := VerifyCleanWorktree(r.dir, attemptID); err != nil {
		t.Errorf("VerifyCleanWorktree should be no-op when evidence dir doesn't exist: %v", err)
	}
}

func writeEvidenceFile(t *testing.T, dir, name, content string) {
	t.Helper()
	if err := os.WriteFile(filepath.Join(dir, name), []byte(content), 0o644); err != nil {
		t.Fatal(err)
	}
}

